/**
 * 脚本执行器
 * 请在此类的run方法中补您你需要实现的业务逻辑
 *
 * @param inputMap 入参集合
 * @return 出参集合
 *
 *
 * 决策组件调用方法
 * 1.格式
 * {方法名称}(inputMap,outputMap,"{组件标识}","{组件出参}->{调用输出}");
 * 如：functionInvoke(inputMap,outputMap,"F00000000","C_N_FUNCTION_OUT2->C_N_FIELD3");
 * 2.说明
 * {方法名称}：functionInvoke（函数调用方法名称）、ruleSetInvoke（规则集调用方法名称）、decisionToolInvoke（决策工具调用方法名称）
 * {组件标识}：组件的标识，如：函数的标识、规则集的标识、决策工具的标识
 * {组件出参}：组件的输出字段名
 * {调用输出}：调用决策组件后的输出字段名
 * {组件出参}->{调用输出}：将{组件出参}赋值给{调用输出}，如果没有“->{调用输出}”，则{组件出参}即为{调用输出}
 * 3.案例
 * 函数F00000000的出参有：C_N_FUNCTION_OUT1，C_N_FUNCTION_OUT3，C_N_FUNCTION_OUT3
 * 调用语句：functionInvoke(inputMap,outputMap,"F00000000","C_N_FUNCTION_OUT1","C_N_FUNCTION_OUT2->C_N_FIELD3");
 * 调用解释：F00000000(函数的标识)的C_N_FUNCTION_OUT1直接输出，C_N_FUNCTION_OUT2映射为C_N_FIELD3，
 * 当不配置选择出参字段，则函数库默认输出所有字段,如functionInvoke(inputMap,outputMap,"F00000000")的输出字段为C_N_FUNCTION_OUT1，C_N_FUNCTION_OUT3，C_N_FUNCTION_OUT3
 *
 */

import com.alibaba.fastjson.*;
import org.apache.commons.lang3.*;
import java.text.SimpleDateFormat;
import java.util.*;
import static cn.tongdun.atreus.engine.function.run.component.DecisionComponentUtils.*;

public Map run(Map inputMap){
    Map outputMap=new HashMap();
    // TODO 请在此处补充需要实现的业务逻辑，结果值put入outputMap中。

    boolean hasEnterprise = false;
    boolean hasPerson = false;
    boolean hasRelated = false;

    if (inputMap != null) {
        hasEnterprise = hasObjectItems(inputMap.get("C_O_ENTERPRISEINFO"));
        hasPerson = hasObjectItems(inputMap.get("C_O_PERSONINFO"));
        hasRelated = hasObjectItems(inputMap.get("C_O_RELATEDCOMPANYINFO"));
    }

    outputMap.put("C_S_HASENTERPRISEINFO", hasEnterprise ? "Y" : "N");
    outputMap.put("C_S_HASPERSONINFO", hasPerson ? "Y" : "N");
    outputMap.put("C_S_HASRELATEDCOMPANYINFO", hasRelated ? "Y" : "N");

    return outputMap;

}

private boolean hasObjectItems(Object raw) {
    if (raw == null) {
        return false;
    }
    if (raw instanceof JSONArray) {
        return hasNonEmptyItem((JSONArray) raw);
    }
    if (raw instanceof List) {
        return hasNonEmptyItem((List) raw);
    }
    if (raw instanceof JSONObject) {
        return !((JSONObject) raw).isEmpty();
    }
    if (raw instanceof Map) {
        return !((Map) raw).isEmpty();
    }

    String text = raw.toString().trim();
    if (text.length() == 0 || "null".equalsIgnoreCase(text) || "[]".equals(text) || "{}".equals(text)) {
        return false;
    }

    try {
        if (text.startsWith("[")) {
            return hasNonEmptyItem(JSONArray.parseArray(text));
        }
        if (text.startsWith("{")) {
            return !JSONObject.parseObject(text).isEmpty();
        }
    } catch (Exception e) {
        return false;
    }

    return false;
}

private boolean hasNonEmptyItem(List list) {
    if (list == null || list.isEmpty()) {
        return false;
    }

    for (int i = 0; i < list.size(); i++) {
        Object item = list.get(i);
        if (item instanceof JSONObject && !((JSONObject) item).isEmpty()) {
            return true;
        }
        if (item instanceof Map && !((Map) item).isEmpty()) {
            return true;
        }
    }

    return false;
}

