    Object keynoListObj = inputMap.get("C_S_MAJORINVESTEDCOMPANYKEYNOS");
    if (keynoListObj != null && StringUtils.isNotBlank(keynoListObj.toString())) {
        keynoList = keynoListObj.toString();
    }

    int index = 0;
    Object indexObj = inputMap.get("C_N_HOLDINGINDEX");
    if (indexObj != null && StringUtils.isNotBlank(indexObj.toString())) {
        try {
            index = Integer.parseInt(indexObj.toString().replace(",", "").trim());
        } catch (Exception e) {
            index = 0;
        }
    }

    // ── 循环控制逻辑：按下标取值，递增下标，判断是否结束 ───────────
    String companyName = "";
    boolean loopEnd = false;

    if (StringUtils.isNotBlank(keynoList)) {
        // 按逗号分割keyno列表，保留尾部空串
        String[] items = keynoList.split(",", -1);
        if (index >= 0 && index < items.length) {
            // 当前下标有效，取出keyno作为持股公司名称
            companyName = items[index];
            // 递增下标供下次循环使用
            index = index + 1;
