            if (index >= items.length) {
                loopEnd = true;
            }
        } else {
            // 下标越界或列表为空，标记循环结束
            loopEnd = true;
        }
    } else {
        // keyno列表为空，直接标记结束
        loopEnd = true;
    }

    // ── 写入出参：透传列表、更新下标、当前名称、结束标识 ───────────
    outputMap.put("C_S_MAJORINVESTEDCOMPANYKEYNOS", keynoList);
    outputMap.put("C_N_HOLDINGINDEX", index);
    outputMap.put("C_S_HOLDINGNAME", companyName);
    outputMap.put("C_B_HOLDINGLOOPEND", loopEnd);

    return outputMap;
}

