import com.alibaba.fastjson.*;
import org.apache.commons.lang3.*;
import java.text.SimpleDateFormat;
import java.util.*;
import static cn.tongdun.atreus.engine.function.run.component.DecisionComponentUtils.*;
import java.math.BigDecimal;
import java.math.RoundingMode;
import java.time.LocalDate;
import java.time.Period;
import java.time.temporal.ChronoUnit;

public Map run(Map inputMap) {
    Map outputMap = new HashMap();

    // ── 读取入参：基线等级和当前等级 ───────────
    String baseLevel = null;
    Object baseObj = inputMap.get("C_S_DBZRQUALLEVEL");
    if (baseObj != null && StringUtils.isNotBlank(baseObj.toString())) {
        baseLevel = baseObj.toString();
    }

    String currentLevel = null;
    Object curObj = inputMap.get("C_S_QUALLEVEL");
    if (curObj != null && StringUtils.isNotBlank(curObj.toString())) {
        currentLevel = curObj.toString();
    }

    // ── 等级映射：特级=4, 一级=3, 二级=2, 三级=1；未知等级按解析失败处理 ───────────
    int baseScore = -999;
    if ("特级".equals(baseLevel)) {
        baseScore = 4;
    } else if ("一级".equals(baseLevel)) {
        baseScore = 3;
    } else if ("二级".equals(baseLevel)) {
        baseScore = 2;
    } else if ("三级".equals(baseLevel)) {
        baseScore = 1;
    }

    int curScore = -999;
    if ("特级".equals(currentLevel)) {
        curScore = 4;
    } else if ("一级".equals(currentLevel)) {
        curScore = 3;
    } else if ("二级".equals(currentLevel)) {
        curScore = 2;
    } else if ("三级".equals(currentLevel)) {
        curScore = 1;
    }

    // ── 降级档位 = 基线分值 - 当前分值，最大不超过3 ───────────
    int dropLevel;
    if (baseScore == -999 || curScore == -999) {
        // 解析失败兜底
        dropLevel = -999;
    } else {
        dropLevel = baseScore - curScore;
        // 上限截断：最大降级不超过3
        if (dropLevel > 3) {
            dropLevel = 3;
        }
        // 负值按0处理（当前等级高于基线不算降级）
        if (dropLevel < 0) {
            dropLevel = 0;
        }
    }

    // ── 写入出参 ───────────
    outputMap.put("C_N_DROPLEVEL", dropLevel);

    return outputMap;
}

