public Map run(Map inputMap) {
    Map outputMap = new HashMap();

    // ── 读取入参：逾期账户数和关注类账户数 ───────────
    BigDecimal odCnt = null;
    Object odObj = inputMap.get("C_N_ODLOANACCTCNT");
    if (odObj != null && StringUtils.isNotBlank(odObj.toString())) {
        try {
            odCnt = new BigDecimal(odObj.toString().replace(",", "").trim());
        } catch (Exception e) {
            odCnt = null;
        }
    }

    BigDecimal attnCnt = null;
    Object attnObj = inputMap.get("C_N_ATTNLOANACCTCNT");
    if (attnObj != null && StringUtils.isNotBlank(attnObj.toString())) {
        try {
            attnCnt = new BigDecimal(attnObj.toString().replace(",", "").trim());
        } catch (Exception e) {
            attnCnt = null;
        }
    }

    // ── 均值计算：两个都为空→null; 仅一个为空→按非空值本身; 都有→(a+b)/2 ───────────
    BigDecimal avg = null;
    if (odCnt == null && attnCnt == null) {
        // 均值类空值策略：全部缺失输出null
        avg = null;
    } else if (odCnt == null) {
        // 仅attnCnt有效，均值即为其本身(除以1)
        avg = attnCnt;
    } else if (attnCnt == null) {
        // 仅odCnt有效，均值即为其本身(除以1)
        avg = odCnt;
    } else {
        // 两个都有值，取平均
        BigDecimal sum = odCnt.add(attnCnt);
        BigDecimal count = new BigDecimal("2");
        avg = sum.divide(count, 1, RoundingMode.HALF_UP);
    }

    // ── 写入出参 ───────────
    outputMap.put("C_F_ODACCTAVG", avg);

    return outputMap;
}

