public Map run(Map inputMap) {
    Map outputMap = new HashMap();

    int pdishonestCount = 0;
    if (inputMap.get("C_N_PDISHONESTFLAG") != null && !inputMap.get("C_N_PDISHONESTFLAG").toString().trim().isEmpty()) {
        pdishonestCount = Integer.valueOf(inputMap.get("C_N_PDISHONESTFLAG").toString().trim());
    }
    int idishonestCount = 0;
    if (inputMap.get("C_N_IDISHONESTFLAG") != null && !inputMap.get("C_N_IDISHONESTFLAG").toString().trim().isEmpty()) {
        idishonestCount = Integer.valueOf(inputMap.get("C_N_IDISHONESTFLAG").toString().trim());
    }

    String shareholderTemp = "";
    if (inputMap.get("C_S_SHAREHOLDER20PCT3MDISHONESTYDETAILQCCTEMP") != null) {
        shareholderTemp = inputMap.get("C_S_SHAREHOLDER20PCT3MDISHONESTYDETAILQCCTEMP").toString();
    }
    String investeeTemp = "";
    if (inputMap.get("C_S_INVESTEE20PCT3MDISHONESTYDETAILQCCTEMP") != null) {
        investeeTemp = inputMap.get("C_S_INVESTEE20PCT3MDISHONESTYDETAILQCCTEMP").toString();
    }

    pdishonestCount += parseDetailCount(shareholderTemp);
    idishonestCount += parseDetailCount(investeeTemp);

    outputMap.put("C_N_PDISHONESTFLAG", pdishonestCount);
    outputMap.put("C_N_IDISHONESTFLAG", idishonestCount);

    return outputMap;
}

private int parseDetailCount(String detail) {
    if (detail == null || detail.trim().isEmpty() || "null".equals(detail.trim())) {
        return 0;
    }
    String d = detail.trim();
    if (d.startsWith("{")) {
        try {
            JSONObject obj = JSONObject.parseObject(d);
            if (obj.containsKey("Paging")) {
                JSONObject paging = obj.getJSONObject("Paging");
                if (paging != null && paging.containsKey("TotalRecords")) {
                    return paging.getIntValue("TotalRecords");
                }
            }
            if (obj.containsKey("Result")) {
                JSONObject result = obj.getJSONObject("Result");
                if (result != null && result.containsKey("Data")) {
                    JSONArray data = result.getJSONArray("Data");
                    if (data != null) { return data.size(); }
                }
            }
        } catch (Exception e) { }
    }
    if (d.startsWith("[")) {
        try {
            JSONArray arr = JSONArray.parseArray(d);
            if (arr != null) { return arr.size(); }
        } catch (Exception e) { }
    }
    try { return Integer.parseInt(d); } catch (Exception e) { return 0; }
}

