import com.alibaba.fastjson.*;
import java.util.*;

public Map run(Map inputMap) {
    Map outputMap = new HashMap();

    List all = new ArrayList();
    boolean anyProvided = false;
    String[] sources = new String[]{
        readString(inputMap, "C_S_MANUALABNORMALITEMS"),
        readString(inputMap, "C_S_SYSTEMABNORMALITEMS"),
        readString(inputMap, "C_S_REVIEWABNORMALITEMS")
    };

    for (int i = 0; i < sources.length; i++) {
        int status = appendItems(sources[i], all);
        if (status < 0) {
            outputMap.put("C_S_ABNORMALITEMS", null);
            return outputMap;
        }
        anyProvided = anyProvided || status > 0;
    }

    if (!anyProvided) {
        outputMap.put("C_S_ABNORMALITEMS", null);
    } else {
        outputMap.put("C_S_ABNORMALITEMS", JSON.toJSONString(all));
    }

    return outputMap;
}

private String readString(Map inputMap, String field) {
    Object value = inputMap.get(field);
    return value == null ? null : value.toString();
}

// return: 0=not provided, 1=provided and parsed, -1=invalid JSON array input
private int appendItems(String source, List all) {
    if (source == null || source.trim().isEmpty()) {
        return 0;
    }

    String text = source.trim();
    if ("NONE".equalsIgnoreCase(text)) {
        return 1;
    }

    if (text.startsWith("[")) {
        try {
            JSONArray arr = JSON.parseArray(text);
            if (arr != null) {
                for (int i = 0; i < arr.size(); i++) {
                    Object item = arr.get(i);
                    addOne(item == null ? null : item.toString(), all);
                }
            }
        } catch (Exception e) {
            return -1;
        }
        return 1;
    }

    String[] codes = text.split(",");
    for (int i = 0; i < codes.length; i++) {
        addOne(codes[i], all);
    }
    return 1;
}

private void addOne(String code, List all) {
    if (code == null) return;
    String trimmed = code.trim();
    if (trimmed.length() == 0 || "NONE".equalsIgnoreCase(trimmed)) return;
    if (!all.contains(trimmed)) {
        all.add(trimmed);
    }
}

